import React, { useState, useRef, useEffect, useCallback } from "react";
import ReactMarkdown from "react-markdown";

const OWNER_NAME = "Abdy Mohameden";
const SYSTEM_PROMPT = `Tu es un assistant IA personnel ultra-avancé, créé exclusivement pour ${OWNER_NAME}.
Tu t'adresses toujours à ${OWNER_NAME} par son prénom avec chaleur et respect.
Tu réponds en français par défaut, arabe ou anglais selon sa préférence.
Tu habites à Nouakchott, Mauritanie — tu adaptes tes réponses à ce contexte.
Tu peux analyser des images, lire des fichiers texte/code/PDF et répondre avec précision.
Tu es expert en développement web, IA, programmation, sciences, et culture mauritanienne.
Tu es proactif, créatif, et toujours prêt à aller au-delà de la question posée.`;

const API_URL = "https://openrouter.ai/api/v1/chat/completions";
const MODEL = "google/gemini-2.0-flash-001";

const SUGGESTIONS = [
  "Analyse cette image pour moi",
  "Explique-moi React hooks",
  "Aide-moi à déboguer mon code",
  "Quelle heure à Nouakchott ?",
  "Recette mauritanienne traditionnelle",
  "Explique-moi l'IA en arabe",
];

function generateId() {
  return Date.now().toString(36) + Math.random().toString(36).slice(2);
}

function newConversation() {
  return { id: generateId(), title: "Nouvelle conversation", messages: [], createdAt: Date.now() };
}

function formatTime(ts) {
  return new Date(ts).toLocaleTimeString("fr-FR", { hour: "2-digit", minute: "2-digit" });
}

function formatDate(ts) {
  const d = new Date(ts);
  const today = new Date();
  const yesterday = new Date(today); yesterday.setDate(today.getDate() - 1);
  if (d.toDateString() === today.toDateString()) return "Aujourd'hui";
  if (d.toDateString() === yesterday.toDateString()) return "Hier";
  return d.toLocaleDateString("fr-FR", { day: "numeric", month: "short" });
}

function fileToBase64(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result.split(",")[1]);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

function fileToText(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.onerror = reject;
    reader.readAsText(file);
  });
}

function TypingDots() {
  return (
    <div className="flex items-center gap-1.5 px-4 py-3">
      {[0, 1, 2].map((i) => (
        <span key={i} className="w-2 h-2 rounded-full bg-violet-400"
          style={{ animation: "bounce 1.2s infinite", animationDelay: `${i * 0.2}s` }} />
      ))}
    </div>
  );
}

function FilePreview({ file, onRemove }) {
  const isImage = file.type.startsWith("image/");
  return (
    <div className="relative group flex-shrink-0">
      {isImage ? (
        <img src={file.preview} alt={file.name}
          className="w-16 h-16 object-cover rounded-xl border border-white/20" />
      ) : (
        <div className="w-16 h-16 rounded-xl border border-white/20 bg-white/5 flex flex-col items-center justify-center gap-1">
          <span className="text-xl">{getFileIcon(file.type)}</span>
          <span className="text-xs text-gray-400 truncate w-14 text-center px-1">{file.name.split(".").pop()}</span>
        </div>
      )}
      <button onClick={onRemove}
        className="absolute -top-1.5 -right-1.5 w-5 h-5 bg-red-500 rounded-full text-white text-xs flex items-center justify-center opacity-0 group-hover:opacity-100 transition">
        ×
      </button>
    </div>
  );
}

function getFileIcon(type) {
  if (type.includes("pdf")) return "📄";
  if (type.includes("text") || type.includes("javascript") || type.includes("json")) return "📝";
  if (type.includes("zip") || type.includes("tar")) return "📦";
  if (type.includes("audio")) return "🎵";
  if (type.includes("video")) return "🎬";
  return "📎";
}

function Message({ msg }) {
  const isUser = msg.role === "user";
  return (
    <div className={`flex gap-3 mb-5 ${isUser ? "flex-row-reverse" : "flex-row"}`}>
      <div className={`flex-shrink-0 w-8 h-8 rounded-xl flex items-center justify-center text-xs font-bold shadow-lg
        ${isUser ? "bg-gradient-to-br from-violet-500 to-purple-700 text-white" : "bg-gradient-to-br from-indigo-500 to-blue-600 text-white"}`}>
        {isUser ? "A" : "✦"}
      </div>
      <div className={`max-w-[78%] flex flex-col gap-1.5 ${isUser ? "items-end" : "items-start"}`}>
        {/* Attachments */}
        {msg.attachments?.length > 0 && (
          <div className="flex flex-wrap gap-2 mb-1">
            {msg.attachments.map((att, i) => (
              <div key={i}>
                {att.type === "image" ? (
                  <img src={`data:${att.mimeType};base64,${att.data}`} alt={att.name}
                    className="max-w-xs max-h-48 rounded-xl border border-white/20 object-cover" />
                ) : (
                  <div className="flex items-center gap-2 bg-white/10 border border-white/20 rounded-xl px-3 py-2">
                    <span>{getFileIcon(att.mimeType)}</span>
                    <span className="text-xs text-gray-300 max-w-32 truncate">{att.name}</span>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
        {/* Text bubble */}
        {msg.content && (
          <div className={`px-4 py-3 rounded-2xl text-sm leading-relaxed shadow-sm
            ${isUser
              ? "bg-gradient-to-br from-violet-600 to-purple-700 text-white rounded-tr-sm"
              : "bg-[#13132a] border border-white/10 text-gray-100 rounded-tl-sm"}`}>
            {isUser
              ? <p className="whitespace-pre-wrap">{msg.content}</p>
              : <div className="msg-content prose prose-invert prose-sm max-w-none"><ReactMarkdown>{msg.content}</ReactMarkdown></div>
            }
          </div>
        )}
        <span className="text-xs text-gray-600 px-1">{formatTime(msg.time)}</span>
      </div>
    </div>
  );
}

export default function App() {
  const [apiKey, setApiKey] = useState(() => localStorage.getItem("abdy_or_key") || "");
  const [keyInput, setKeyInput] = useState(apiKey);
  const [showSettings, setShowSettings] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const [conversations, setConversations] = useState(() => {
    try { const s = localStorage.getItem("abdy_convs_v2"); return s ? JSON.parse(s) : [newConversation()]; }
    catch { return [newConversation()]; }
  });

  const [activeId, setActiveId] = useState(() => {
    try { const s = localStorage.getItem("abdy_convs_v2"); if (s) return JSON.parse(s)[0]?.id; }
    catch {} return null;
  });

  const [input, setInput] = useState("");
  const [attachments, setAttachments] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [editingId, setEditingId] = useState(null);
  const [editTitle, setEditTitle] = useState("");
  const [dragOver, setDragOver] = useState(false);

  const bottomRef = useRef(null);
  const inputRef = useRef(null);
  const fileInputRef = useRef(null);

  const activeConv = conversations.find((c) => c.id === activeId) || conversations[0];

  useEffect(() => {
    if (!activeId && conversations.length > 0) setActiveId(conversations[0].id);
  }, []);

  useEffect(() => {
    localStorage.setItem("abdy_convs_v2", JSON.stringify(conversations));
  }, [conversations]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [activeConv?.messages, loading]);

  const saveKey = () => {
    localStorage.setItem("abdy_or_key", keyInput);
    setApiKey(keyInput);
    setShowSettings(false);
    setError("");
  };

  const createConversation = () => {
    const conv = newConversation();
    setConversations((prev) => [conv, ...prev]);
    setActiveId(conv.id);
    setInput(""); setAttachments([]); setError("");
    setTimeout(() => inputRef.current?.focus(), 100);
  };

  const deleteConversation = (id) => {
    setConversations((prev) => {
      const updated = prev.filter((c) => c.id !== id);
      if (updated.length === 0) { const f = newConversation(); setActiveId(f.id); return [f]; }
      if (activeId === id) setActiveId(updated[0].id);
      return updated;
    });
  };

  const handleFiles = useCallback(async (files) => {
    const processed = [];
    for (const file of files) {
      if (file.size > 20 * 1024 * 1024) { setError(`❌ ${file.name} dépasse 20MB`); continue; }
      const isImage = file.type.startsWith("image/");
      const preview = isImage ? URL.createObjectURL(file) : null;
      processed.push({ file, name: file.name, type: file.type, preview, isImage });
    }
    setAttachments((prev) => [...prev, ...processed]);
  }, []);

  const onFileChange = (e) => { if (e.target.files?.length) handleFiles(Array.from(e.target.files)); e.target.value = ""; };

  const onDrop = (e) => {
    e.preventDefault(); setDragOver(false);
    if (e.dataTransfer.files?.length) handleFiles(Array.from(e.dataTransfer.files));
  };

  const sendMessage = async () => {
    if ((!input.trim() && attachments.length === 0) || loading || !activeConv) return;
    if (!apiKey) { setError("⚠️ Configure ta clé API dans ⚙️"); return; }

    // Build message content
    const contentParts = [];
    const attachmentMeta = [];

    for (const att of attachments) {
      const b64 = await fileToBase64(att.file);
      if (att.isImage) {
        contentParts.push({ type: "image_url", image_url: { url: `data:${att.type};base64,${b64}` } });
        attachmentMeta.push({ type: "image", name: att.name, mimeType: att.type, data: b64 });
      } else {
        try {
          const text = await fileToText(att.file);
          contentParts.push({ type: "text", text: `📎 Fichier: ${att.name}\n\`\`\`\n${text.slice(0, 8000)}\n\`\`\`` });
          attachmentMeta.push({ type: "file", name: att.name, mimeType: att.type });
        } catch {
          contentParts.push({ type: "text", text: `📎 Fichier joint: ${att.name} (binaire)` });
          attachmentMeta.push({ type: "file", name: att.name, mimeType: att.type });
        }
      }
    }

    if (input.trim()) contentParts.push({ type: "text", text: input.trim() });
    else if (attachmentMeta.length > 0) contentParts.push({ type: "text", text: "Analyse ce fichier/image et dis-moi ce que tu vois." });

    const userMsg = {
      role: "user",
      content: input.trim(),
      attachments: attachmentMeta,
      time: Date.now(),
    };

    const apiContent = contentParts.length === 1 && contentParts[0].type === "text"
      ? contentParts[0].text
      : contentParts;

    const isFirst = activeConv.messages.length === 0;
    const autoTitle = isFirst ? (input.trim() || attachmentMeta[0]?.name || "Nouveau chat").slice(0, 40) : activeConv.title;

    setConversations((prev) => prev.map((c) =>
      c.id === activeId ? { ...c, messages: [...c.messages, userMsg], title: autoTitle } : c
    ));
    setInput(""); setAttachments([]); setLoading(true); setError("");

    const historyMessages = [...activeConv.messages, userMsg];

    try {
      const res = await fetch(API_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${apiKey}`,
          "HTTP-Referer": "http://localhost:3000",
          "X-Title": "Abdy AI",
        },
        body: JSON.stringify({
          model: MODEL,
          messages: [
            { role: "system", content: SYSTEM_PROMPT },
            ...historyMessages.slice(0, -1).map(({ role, content }) => ({ role, content: content || "" })),
            { role: "user", content: apiContent },
          ],
        }),
      });

      if (!res.ok) { const e = await res.json(); throw new Error(e.error?.message || `Erreur ${res.status}`); }
      const data = await res.json();
      const aiText = data.choices?.[0]?.message?.content || "Désolé, pas de réponse.";

      setConversations((prev) => prev.map((c) =>
        c.id === activeId
          ? { ...c, messages: [...c.messages, userMsg, { role: "assistant", content: aiText, time: Date.now() }] }
          : c
      ));
    } catch (e) {
      setError(`❌ ${e.message}`);
    } finally {
      setLoading(false);
      inputRef.current?.focus();
    }
  };

  const handleKey = (e) => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } };

  // Group conversations by date
  const grouped = conversations.reduce((acc, conv) => {
    const label = formatDate(conv.createdAt);
    if (!acc[label]) acc[label] = [];
    acc[label].push(conv);
    return acc;
  }, {});

  return (
    <div className="flex h-screen bg-[#080810] text-white overflow-hidden"
      onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
      onDragLeave={() => setDragOver(false)}
      onDrop={onDrop}>

      {/* DRAG OVERLAY */}
      {dragOver && (
        <div className="absolute inset-0 z-50 bg-violet-900/60 border-2 border-violet-400 border-dashed flex items-center justify-center backdrop-blur-sm">
          <div className="text-center">
            <div className="text-6xl mb-4">📂</div>
            <p className="text-xl font-bold text-violet-200">Dépose tes fichiers ici</p>
            <p className="text-gray-400 text-sm mt-1">Images, code, texte, PDF...</p>
          </div>
        </div>
      )}

      {/* ══ SIDEBAR ══ */}
      <div className={`flex flex-col transition-all duration-300 bg-[#0b0b18] border-r border-white/8 ${sidebarOpen ? "w-68" : "w-0 overflow-hidden"}`}
        style={{ width: sidebarOpen ? "272px" : "0px" }}>

        {/* Logo */}
        <div className="flex items-center justify-between px-4 pt-5 pb-4 border-b border-white/8">
          <div className="flex items-center gap-2.5">
            <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-violet-500 via-indigo-500 to-blue-600 flex items-center justify-center shadow-lg shadow-violet-900/50 text-sm font-bold">✦</div>
            <div>
              <p className="font-bold text-sm text-white leading-none">Abdy AI</p>
              <p className="text-xs text-violet-400 mt-0.5">Assistant personnel</p>
            </div>
          </div>
          <button onClick={createConversation}
            className="w-8 h-8 rounded-xl bg-violet-600/80 hover:bg-violet-500 flex items-center justify-center transition shadow-md text-base font-bold"
            title="Nouveau chat">+</button>
        </div>

        {/* Conversations */}
        <div className="flex-1 overflow-y-auto py-3 px-2 space-y-4">
          {Object.entries(grouped).map(([label, convs]) => (
            <div key={label}>
              <p className="text-xs text-gray-600 font-semibold uppercase tracking-wider px-3 mb-1">{label}</p>
              {convs.map((conv) => (
                <div key={conv.id} onClick={() => { setActiveId(conv.id); setError(""); }}
                  className={`group flex items-center gap-2 px-3 py-2.5 rounded-xl cursor-pointer mb-0.5 transition-all
                    ${activeId === conv.id ? "bg-violet-600/15 border border-violet-500/25 shadow-sm" : "hover:bg-white/4 border border-transparent"}`}>
                  <div className="flex-1 min-w-0">
                    {editingId === conv.id ? (
                      <input autoFocus value={editTitle}
                        onChange={(e) => setEditTitle(e.target.value)}
                        onBlur={() => { setConversations((p) => p.map((c) => c.id === conv.id ? { ...c, title: editTitle || "Sans titre" } : c)); setEditingId(null); }}
                        onKeyDown={(e) => { if (e.key === "Enter") { setConversations((p) => p.map((c) => c.id === conv.id ? { ...c, title: editTitle || "Sans titre" } : c)); setEditingId(null); } }}
                        onClick={(e) => e.stopPropagation()}
                        className="w-full bg-black/40 border border-violet-500/60 rounded-lg px-2 py-0.5 text-xs text-white focus:outline-none" />
                    ) : (
                      <>
                        <p className="text-xs font-medium truncate text-gray-200 leading-none">{conv.title}</p>
                        <p className="text-xs text-gray-600 mt-1">{conv.messages.length} message{conv.messages.length !== 1 ? "s" : ""}</p>
                      </>
                    )}
                  </div>
                  <div className="hidden group-hover:flex gap-1" onClick={(e) => e.stopPropagation()}>
                    <button onClick={() => { setEditingId(conv.id); setEditTitle(conv.title); }}
                      className="w-6 h-6 rounded-lg hover:bg-white/10 flex items-center justify-center text-gray-500 hover:text-white text-xs transition">✏️</button>
                    <button onClick={() => deleteConversation(conv.id)}
                      className="w-6 h-6 rounded-lg hover:bg-red-900/40 flex items-center justify-center text-gray-500 hover:text-red-400 text-xs transition">🗑</button>
                  </div>
                </div>
              ))}
            </div>
          ))}
        </div>

        {/* Sidebar footer */}
        <div className="px-4 py-3 border-t border-white/8">
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-green-400 animate-pulse"></div>
            <p className="text-xs text-gray-500">Gemini 2.0 Flash · {conversations.length} chat{conversations.length !== 1 ? "s" : ""}</p>
          </div>
        </div>
      </div>

      {/* ══ MAIN AREA ══ */}
      <div className="flex flex-col flex-1 min-w-0">

        {/* Header */}
        <header className="flex items-center justify-between px-5 py-3 border-b border-white/8 bg-[#0b0b18]/80 backdrop-blur-sm">
          <div className="flex items-center gap-3">
            <button onClick={() => setSidebarOpen(!sidebarOpen)}
              className="w-8 h-8 rounded-xl bg-white/5 hover:bg-white/10 flex items-center justify-center transition text-gray-400 hover:text-white text-sm">
              {sidebarOpen ? "◀" : "▶"}
            </button>
            <div>
              <h1 className="font-semibold text-sm text-white truncate max-w-sm leading-none">
                {activeConv?.title || "Nouvelle conversation"}
              </h1>
              <p className="text-xs text-gray-600 mt-0.5">{activeConv?.messages.length || 0} messages</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={createConversation}
              className="hidden sm:flex items-center gap-1.5 text-xs text-gray-400 hover:text-white px-3 py-1.5 rounded-xl hover:bg-white/8 border border-white/8 transition">
              <span className="text-base leading-none">+</span> Nouveau chat
            </button>
            <button onClick={() => setShowSettings(!showSettings)}
              className={`w-8 h-8 rounded-xl flex items-center justify-center transition text-sm
                ${showSettings ? "bg-violet-600 text-white" : "bg-white/5 hover:bg-white/10 text-gray-400 hover:text-white"}`}>
              ⚙️
            </button>
          </div>
        </header>

        {/* Settings panel */}
        {showSettings && (
          <div className="bg-[#0f0f20] border-b border-white/8 px-5 py-4">
            <div className="flex items-center gap-2 mb-3">
              <div className="w-2 h-2 rounded-full bg-green-400"></div>
              <p className="text-xs text-green-400 font-semibold">Modèle : Gemini 2.0 Flash (OpenRouter)</p>
            </div>
            <div className="flex gap-2">
              <input type="password" value={keyInput} onChange={(e) => setKeyInput(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && saveKey()}
                placeholder="sk-or-v1-..."
                className="flex-1 bg-black/40 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white focus:outline-none focus:border-violet-500 font-mono transition" />
              <button onClick={saveKey}
                className="px-5 py-2.5 bg-violet-600 hover:bg-violet-500 text-white rounded-xl text-sm font-bold transition shadow-lg shadow-violet-900/30">
                Sauvegarder
              </button>
            </div>
            <p className="text-xs text-gray-600 mt-2">Clé API sur <a href="https://openrouter.ai/keys" target="_blank" rel="noreferrer" className="text-violet-400 hover:underline">openrouter.ai/keys</a></p>
          </div>
        )}

        {/* Messages */}
        <main className="flex-1 overflow-y-auto px-6 py-6">
          {(!activeConv || activeConv.messages.length === 0) && (
            <div className="flex flex-col items-center justify-center h-full gap-5 text-center pb-16">
              <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-violet-500 via-indigo-500 to-blue-600 flex items-center justify-center text-2xl shadow-2xl shadow-violet-900/50">✦</div>
              <div>
                <h2 className="text-xl font-bold text-white">Bonjour, Abdy ! 👋</h2>
                <p className="text-gray-500 text-sm mt-1 max-w-sm">Je peux analyser tes images, lire tes fichiers, et répondre à toutes tes questions.</p>
              </div>
              <div className="flex flex-wrap gap-2 justify-center max-w-lg mt-1">
                {SUGGESTIONS.map((s) => (
                  <button key={s} onClick={() => { setInput(s); inputRef.current?.focus(); }}
                    className="px-3 py-2 bg-white/5 hover:bg-violet-600/20 border border-white/8 hover:border-violet-500/40 rounded-xl text-xs text-gray-400 hover:text-white transition">
                    {s}
                  </button>
                ))}
              </div>
              <div className="mt-2 flex items-center gap-2 text-xs text-gray-600">
                <span>📎 Glisse-dépose des fichiers</span>
                <span>·</span>
                <span>🖼️ Images supportées</span>
                <span>·</span>
                <span>📝 Code & texte</span>
              </div>
            </div>
          )}

          {activeConv?.messages.map((msg, i) => <Message key={i} msg={msg} />)}

          {loading && (
            <div className="flex gap-3 mb-4">
              <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-indigo-500 to-blue-600 flex items-center justify-center text-xs shadow-lg">✦</div>
              <div className="bg-[#13132a] border border-white/10 rounded-2xl rounded-tl-sm">
                <TypingDots />
              </div>
            </div>
          )}

          {error && (
            <div className="mx-auto max-w-lg bg-red-900/15 border border-red-500/25 text-red-400 text-sm px-4 py-3 rounded-xl flex items-start gap-2">
              <span className="flex-shrink-0 mt-0.5">⚠️</span>
              <span>{error}</span>
            </div>
          )}
          <div ref={bottomRef} />
        </main>

        {/* Input area */}
        <footer className="px-5 pb-5 pt-3 border-t border-white/8 bg-[#0b0b18]/80 backdrop-blur-sm">
          {/* Attachments preview */}
          {attachments.length > 0 && (
            <div className="flex gap-2 mb-3 flex-wrap">
              {attachments.map((att, i) => (
                <FilePreview key={i} file={att} onRemove={() => setAttachments((prev) => prev.filter((_, idx) => idx !== i))} />
              ))}
            </div>
          )}

          <div className="flex gap-2 items-end">
            {/* File upload button */}
            <button onClick={() => fileInputRef.current?.click()}
              className="flex-shrink-0 w-10 h-10 rounded-xl bg-white/5 hover:bg-white/10 border border-white/10 hover:border-violet-500/40 flex items-center justify-center transition text-gray-400 hover:text-violet-400"
              title="Joindre un fichier ou une image">
              📎
            </button>
            <input ref={fileInputRef} type="file" multiple accept="image/*,.pdf,.txt,.js,.jsx,.ts,.tsx,.py,.json,.csv,.md,.html,.css,.xml,.yaml,.yml,.sh,.c,.cpp,.java,.rs,.go"
              onChange={onFileChange} className="hidden" />

            {/* Text input */}
            <div className="flex-1 relative">
              <textarea ref={inputRef} value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={handleKey}
                placeholder={attachments.length > 0 ? "Décris ce que tu veux faire avec ces fichiers…" : "Pose ta question, Abdy… (ou glisse un fichier)"}
                rows={1}
                className="w-full resize-none bg-white/5 border border-white/10 focus:border-violet-500/60 rounded-2xl px-4 py-3 text-sm text-white placeholder-gray-600 focus:outline-none transition max-h-40 overflow-y-auto"
                style={{ lineHeight: "1.6" }}
                onInput={(e) => { e.target.style.height = "auto"; e.target.style.height = Math.min(e.target.scrollHeight, 160) + "px"; }} />
            </div>

            {/* Send button */}
            <button onClick={sendMessage} disabled={loading || (!input.trim() && attachments.length === 0)}
              className={`flex-shrink-0 w-10 h-10 rounded-xl flex items-center justify-center transition text-base shadow-lg
                ${loading || (!input.trim() && attachments.length === 0)
                  ? "bg-white/5 text-gray-600 cursor-not-allowed border border-white/5"
                  : "bg-gradient-to-br from-violet-600 to-indigo-600 hover:from-violet-500 hover:to-indigo-500 text-white shadow-violet-900/50 hover:scale-105 active:scale-95"}`}>
              {loading ? "⏳" : "➤"}
            </button>
          </div>
          <p className="text-center text-xs text-gray-700 mt-2">Entrée pour envoyer · Shift+Entrée nouvelle ligne · 📎 Images & fichiers supportés</p>
        </footer>
      </div>
    </div>
  );
}
